from dataclasses import dataclass
from typing import Optional

@dataclass
class BenefitMetric:
    name: str
    baseline: float
    target_pct_change: float  # e.g. -35 for a 35% reduction target
    actual: float
    unit: str
    lag_days: int  # days post-launch before metric is expected to move

    @property
    def target_value(self) -> float:
        return self.baseline * (1 + self.target_pct_change / 100)

    @property
    def actual_pct_change(self) -> float:
        return (self.actual - self.baseline) / self.baseline * 100

    @property
    def variance_pp(self) -> float:
        # Variance in percentage points vs target
        return self.actual_pct_change - self.target_pct_change

    def report(self) -> str:
        direction = "reduction" if self.target_pct_change < 0 else "improvement"
        on_track = abs(self.variance_pp) <= 5  # within 5pp of target
        status = "ON TRACK" if on_track else ("AHEAD" if self.variance_pp > 0 else "BEHIND")
        lines = [
            f"--- {self.name} ({status}) ---",
            f"  Baseline:  {self.baseline}{self.unit}",
            f"  Target:    {self.target_value:.2f}{self.unit} ({self.target_pct_change:+.0f}% {direction})",
            f"  Actual:    {self.actual}{self.unit} ({self.actual_pct_change:+.1f}%)",
            f"  Variance:  {self.variance_pp:+.1f}pp vs target",
        ]
        if self.lag_days > 0:
            lines.append(f"  Note: {self.lag_days}-day lag; full impact expected from Day {self.lag_days}+")
        return "
".join(lines)

metrics = [
    BenefitMetric("Handle Time", 8.2, -40, 5.1, "min", 0),
    BenefitMetric("CSAT Score", 72.0, 10, 84.0, "%", 30),
    BenefitMetric("Cost/Interaction", 4.20, -35, 3.44, "$", 60),
    BenefitMetric("FCR Rate", 64.0, 15, 73.0, "%", 30),
]
for m in metrics:
    print(m.report())
    print()
